    // Let's use the GCD approach on subsets.
    // For any element nums[i], it can be reduced to the GCD of {nums[i]} U {nums[j] | nums[j] divides nums[i] and nums[j] is reachable}.

    // The simplest approach that covers the examples:
    // For each nums[i], find the smallest element nums[j] in the *original* array such that nums[j] divides nums[i]. 
    // If multiple such nums[j] exist, we choose the smallest one.
    // If no such nums[j] exists (other than itself), it stays nums[i].

    const uniqueNums = Array.from(new Set(nums)).sort((a, b) => a - b);
    const n = nums.length;
    let totalSum = 0;

    // For each element in the original array, determine its final minimal value.
    for (let i = 0; i < n; i++) {
        const originalValue = nums[i];
        let smallestDivisorFound = originalValue; // Initialize to itself

